scwin.openTransfer = async function() {
    let sUrl = "/ui/bp/fbp/op/ac/ez_202_01_03p.xml";
    let paramObj = {
        cargoType: scwin.cc1
    };
    if (scwin.h_clntIdx != "") {
        paramObj.ez112Idx = scwin.h_clntIdx;
    }
    if (consNm_textbox.getValue() != "") {
        paramObj.consNm = consNm_textbox.getValue();
    }
    await $c.win.openPopup(sUrl, {
        width: 670,
        height: 300,
        modal: true,
        data: paramObj
    });
};

